const base = env.get('JELLYFIN_URL');
const key = env.get('JELLYFIN_API_KEY');
const userId = env.get('JELLYFIN_USER_ID');
if (!base || !key) { node.error('JELLYFIN_URL or JELLYFIN_API_KEY not set'); return null; }
const { query, media_type, limit } = msg.payload;
if (media_type === 'Episode') {
  let series = null;
  try {
    const sp = new URLSearchParams({ searchTerm: query, Recursive: 'true', Limit: '1', IncludeItemTypes: 'Series' });
    if (userId) sp.set('UserId', userId);
    const u = new URL(`${base}/Items?${sp}`);
    const port = u.port ? parseInt(u.port) : (u.protocol === 'https:' ? 443 : 80);
    const mod = u.protocol === 'https:' ? https : http;
    const sd = await Promise.race([
      new Promise((resolve, reject) => {
        const req = mod.request({ hostname: u.hostname, port, path: u.pathname + u.search, method: 'GET', headers: { 'X-Emby-Token': key } }, res => {
          let d = ''; res.on('data', c => d += c); res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { reject(e); } });
        });
        req.on('error', reject); req.end();
      }),
      new Promise((_, reject) => setTimeout(() => reject(new Error('lookup timeout')), 4000))
    ]);
    series = sd.Items?.[0] || null;
  } catch(e) { node.warn('Series lookup: ' + e.message); }
  if (series) {
    const ep = new URLSearchParams({ Recursive: 'true', Limit: String(limit || 10), Fields: 'Overview,SeriesName,SeasonName,IndexNumber,ParentIndexNumber' });
    if (userId) ep.set('UserId', userId);
    msg.url = `${base}/Shows/${series.Id}/Episodes?${ep}`;
  } else {
    const params = new URLSearchParams({ searchTerm: query, Recursive: 'true', Limit: String(limit || 10), IncludeItemTypes: 'Episode', Fields: 'Overview,SeriesName,SeasonName,IndexNumber,ParentIndexNumber' });
    if (userId) params.set('UserId', userId);
    msg.url = `${base}/Items?${params}`;
  }
} else {
  const params = new URLSearchParams({ searchTerm: query, Recursive: 'true', Limit: String(limit || 10), Fields: 'Overview,SeriesName,SeasonName,IndexNumber,ParentIndexNumber,ChildCount' });
  if (media_type) params.set('IncludeItemTypes', media_type);
  if (userId) params.set('UserId', userId);
  msg.url = `${base}/Items?${params}`;
}
msg.headers = { 'X-Emby-Token': key };
return msg;

if (msg.statusCode >= 400) { msg.payload = { error: `HTTP ${msg.statusCode}` }; return msg; }
const base = env.get('JELLYFIN_URL');
const key = env.get('JELLYFIN_API_KEY');
const fetchSeasonCount = (id) => new Promise(resolve => {
  try {
    const u = new URL(`${base}/Shows/${id}/Seasons`);
    const port = u.port ? parseInt(u.port) : (u.protocol === 'https:' ? 443 : 80);
    const mod = u.protocol === 'https:' ? https : http;
    const req = mod.request({ hostname: u.hostname, port, path: u.pathname + u.search, method: 'GET', headers: { 'X-Emby-Token': key } }, res => {
      let d = ''; res.on('data', c => d += c); res.on('end', () => { try { resolve(JSON.parse(d).TotalRecordCount || 0); } catch(e) { resolve(0); } });
    });
    req.on('error', () => resolve(0)); req.setTimeout(3000, () => { req.destroy(); resolve(0); }); req.end();
  } catch(e) { resolve(0); }
});
const items = await Promise.all((msg.payload.Items || []).map(async i => {
  const item = { id: i.Id, name: i.Name, type: i.Type, year: i.ProductionYear || null, overview: i.Overview ? i.Overview.slice(0, 200) : null };
  if (i.SeriesName) item.seriesName = i.SeriesName;
  if (i.SeasonName) item.seasonName = i.SeasonName;
  if (i.ParentIndexNumber != null) item.seasonNumber = i.ParentIndexNumber;
  if (i.IndexNumber != null) item.episodeNumber = i.IndexNumber;
  if (i.Type === 'Series') item.seasonCount = await fetchSeasonCount(i.Id);
  return item;
}));
msg.payload = JSON.stringify({ total: msg.payload.TotalRecordCount, items });
return msg;

const base = env.get('JELLYFIN_URL');
const externalBase = env.get('JELLYFIN_EXTERNAL_URL') || base;
const key = env.get('JELLYFIN_API_KEY');
const { item_id, width } = msg.payload;
msg.url = `${base}/Items/${item_id}/Images/Primary?maxWidth=${width || 400}&quality=80`;
msg.imageUrl = `${externalBase}/Items/${item_id}/Images/Primary?maxWidth=${width || 400}&quality=80&api_key=${key}`;
msg.headers = { 'X-Emby-Token': key };
return msg;

if (msg.statusCode >= 400) { msg.payload = { error: `HTTP ${msg.statusCode}` }; return msg; }
msg.payload = `![poster](${msg.imageUrl})`;
return msg;
